WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('divide','Error Handling','function','go','Divide with Error','Divide two integers and return the result as a float64. Return error if dividing by zero.','Divide','[]interface{}',ARRAY['int','int']::text[],ARRAY['Return []interface{}{result, error.Error()} or {0,""} on success.','If b is 0, return {0.0, "division by zero"}.','Use float64 for the division result (convert a and b first).'],2,70,ARRAY['errors','basic'],true,'MANUAL:divide',$$Divide two numbers, returning error on division by zero.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[10,2]'::jsonb,'[5.0,""]',false,1),('[7,3]'::jsonb,'[2.3333333333333335,""]',false,2),('[5,0]'::jsonb,'[0.0,"division by zero"]',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('parse-int','Error Handling','function','go','Parse Integer with Error Handling','Parse a string into an integer. Return the integer or an error message if parsing fails.','ParseIntSafe','[]interface{}',ARRAY['string']::text[],ARRAY['Use strconv.Atoi to parse the string.','Return []interface{}{parsedValue, ""} on success.','On error, return {0, error message string}.'],1,60,ARRAY['errors','parsing','basic'],true,'MANUAL:parse-int',$$Parse a string to int with error handling.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
