WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('safe-slice-access','Error Handling','function','go','Safe Slice Access','Return the element at index i from a slice. Return an error if index is out of bounds.','SafeAccess','[]interface{}',ARRAY['[]int','int']::text[],ARRAY['Check if i < 0 or i >= len(slice).','Return {0, "index out of bounds"} on error.','Return {slice[i], ""} on success.'],1,50,ARRAY['errors','slices','basic'],true,'MANUAL:safe-slice-access',$$Safely access a slice element with bounds checking.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
