WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('method-receiver-value-vs-pointer','OOP & Composition','function','go','Method Receiver Types','Demonstrate the difference between value and pointer receivers. Given initial value, apply methods and return final value.','ReceiverDemo','int',ARRAY['int']::text[],ARRAY['Create Counter struct with Value int.','AddValue(takes value receiver, returns copy). AddPtr(takes pointer receiver, modifies original).','Return the final value after operations.'],2,80,ARRAY['oop','methods','receivers','medium'],true,'MANUAL:method-receiver-value-vs-pointer',$$Demonstrate value vs pointer method receivers.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[5]'::jsonb,'10',false,1),('[0]'::jsonb,'0',false,2),('[-3]'::jsonb,'3',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('constructor-pattern','OOP & Composition','function','go','Constructor Pattern','Design a Config struct with fields Host, Port, Timeout. Implement a NewConfig function with defaults: localhost, 8080, 30.','NewConfig','map[string]interface{}',ARRAY['string','int','int']::text[],ARRAY['Define Config struct with Host, Port, Timeout.','If host is empty, default to "localhost". If port is 0, default to 8080. If timeout is 0, default to 30.','Return map with config fields.'],1,60,ARRAY['oop','constructor','structs','basic'],true,'MANUAL:constructor-pattern',$$Design a Config struct with constructor and defaults.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["",0,0]'::jsonb,'{"host":"localhost","port":8080,"timeout":30}',false,1),('["example.com",9090,60]'::jsonb,'{"host":"example.com","port":9090,"timeout":60}',false,2),('["test",0,10]'::jsonb,'{"host":"test","port":8080,"timeout":10}',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;
